		}
		if m.ContextLength > 0 {
			cl := m.ContextLength
			entry.ContextLength = &cl
		}
		entries = append(entries, entry)
	}

	return &ProviderModelsResult{
		Name:      name,
		Kind:      kind,
		Models:    entries,
		BaseURL:   baseURL,
